{
  "title": "डीएनडीबी स्ट्रीम्स के उद्देश्य",
  "group": "DynamoDB Streams",
  "options": [
    {
      "text": "अतिरिक्त डेटा कॉपियाँ संग्रहित करें"
    },
    {
      "text": "ग्रीन वेंडर्स के लिए डीएनडीबी क्रेडिट्स",
      "hint": "वाकई?"
    },
    {
      "text": "लिखने के प्रदर्शन को बढ़ाएं",
      "hint": "स्ट्रीम्स होते हैं"
    },
    {
      "text": "इवेंट-ड्राइव्ड एर्किटेक्चर के लिए आइटम-लेवल परिवर्तन पकड़ें"
    },
    {
      "text": "ग्लोबल सेकेंडरी इंडेक्स के विकल्प",
      "hint": "क्या आप अनुमान लगा रहे हैं?"
    }
  ],
  "questionProse": [
    "डीएनडीबी स्ट्रीम्स के प्राथमिक उपयोग क्या है?"
  ],
  "explanationProse": [
    "डीएनडीबी स्ट्रीम्स:\n    - आइटम-लेवल परिवर्तनों को पकड़ते हैं\n    - इवेंट-ड्राइव्ड एर्किटेक्चर को सक्षम करते हैं\n    - लैम्ब्डा फंक्शन को ट्रिगर करते हैं\n    - क्रॉस-रीजन रिप्लिकेशन का समर्थन करते हैं\n    - निकट वास्तविक समय में डेटा प्रसारण प्रदान करते हैं\n\n    [DynamoDB स्ट्रीम्स अवलोकन](https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/Streams.html)"
  ]
}
